import {
  BooleanField,
  NumberField,
  StringField,
  ClassField,
} from "../../../decorators/field.decorators.ts";

export class RefundDetailDto {
  @StringField()
  transactionId!: string;

  @StringField()
  cidNo!: string;

  @NumberField()
  amount!: number;

  @StringField()
  status!: string;
}

export class RefundResponseDto {
  @BooleanField()
  success!: boolean;

  @StringField()
  poolId!: string;

  @NumberField()
  totalRefundAmount!: number;

  @NumberField()
  refundCount!: number;

  @ClassField(() => RefundDetailDto, { isArray: true })
  refundDetails!: RefundDetailDto[];

  @StringField()
  message!: string;
}
